#!/usr/bin/env python3
# Generated by scripts/generate_activities.py
# To update: edit quiz-data/make-the-linter-happy.json and re-run the generator.
"""Make the Linter Happy

A small typed Python project seeded with real findings: ruff check violations, ruff format diffs, ty type errors, and one failing pytest. Fix them one at a time -- run the tool, read the FIRST error, fix the smallest thing, rerun -- until all four gates are green. The launcher reruns all four tools itself to check your work.
"""
import os, shutil, subprocess, sys, tempfile, zipfile

# -- Crypto / obfuscation --
import hashlib as _hl, hmac as _hm

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "0bea94f57e0b95bb8dc685aba993f99fa8a42172e8e1e51db6440525fd2806da9b4e9d46d7e95ac74c7d7db1c94aa4ccb43e8bdd0d60810e2791"

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac("sha256", key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b"", 0, b""
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

# -- Helpers --
import textwrap as _tw

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)


SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

def _extract_repo():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")
    work_dir = tempfile.mkdtemp(prefix="make-the-linter-happy-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
        # zipfile.extractall() does not restore Unix permission bits, so any
        # script shipped in the zip (e.g. lint.sh) loses its executable bit
        # here. Restore the mode recorded in the archive for each file.
        for info in zf.infolist():
            mode = info.external_attr >> 16
            if mode:
                os.chmod(os.path.join(work_dir, info.filename), mode)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    return work_dir, os.path.join(work_dir, entries[0])

def _make_rcfile(repo_dir):
    banner_text = """
      ============================================================
       Make the Linter Happy
      ============================================================

       This little snack-stand ledger has problems on four fronts.
       Your job: make all four quality tools happy, one finding at a
       time.
       
       Step 1 -- see what the linter thinks
         ruff check .
         Read the FIRST error only. Fix the smallest thing it points
         at, then run ruff check . again. Repeat until it says
         'All checks passed!'
       
       Step 2 -- see what the formatter thinks
         ruff format --check .
         It lists files it WOULD reformat. Run 'ruff format .' to let
         it fix the layout for you, then --check again to confirm.
       
       Step 3 -- see what the type checker thinks
         ty check .
         Each diagnostic names a file, a line, and the type promise
         that was broken. Fix the code (never silence the checker).
       
       Step 4 -- run the tests
         pytest -q
         One test fails. The test states what the menu promises;
         the code disagrees. Decide which one is right and fix it.
       
       When all four commands pass, type 'exit'. The launcher reruns
       all four tools itself -- it trusts the tools, not you -- and
       unlocks the passphrase only when every gate is green.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@make-the-linter-happy:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << 'BANNER'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()
    return rcfile

def _drop_to_shell(repo_dir):
    rcfile = _make_rcfile(repo_dir)
    shell = os.environ.get("SHELL", "/bin/bash")
    try:
        subprocess.run([shell, "--rcfile", rcfile.name])
    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass

def run_shell_drop_once():
    work_dir, repo_dir = _extract_repo()
    _drop_to_shell(repo_dir)
    return repo_dir, work_dir

def run_shell_drop_with_retry(is_ready, not_ready_lines):
    work_dir, repo_dir = _extract_repo()
    while True:
        _drop_to_shell(repo_dir)
        if is_ready(repo_dir):
            return repo_dir, work_dir
        print()
        for line in not_ready_lines(repo_dir):
            print(line)
        print()
        try:
            again = input("  Try again? [y/n] ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print()
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None
        if again != "y":
            shutil.rmtree(work_dir, ignore_errors=True)
            return None, None

def run_shell_drop_validated(check):
    work_dir, repo_dir = _extract_repo()
    try:
        while True:
            _drop_to_shell(repo_dir)
            print()
            _banner("Make the Linter Happy -- Checking Your Work")
            print()
            passphrase, feedback = check(repo_dir)
            if passphrase is not None:
                _show_passphrase(passphrase)
                return True
            for line in feedback:
                print(line)
            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                return False
            if again != "y":
                return False
            print()
    finally:
        shutil.rmtree(work_dir, ignore_errors=True)

class ActivityEngine:
    """Core build/run/validate logic for Make the Linter Happy; importable without a TTY."""

    slug = "make-the-linter-happy"
    title = "Make the Linter Happy"
    description = 'A small typed Python project seeded with real findings: ruff check violations, ruff format diffs, ty type errors, and one failing pytest. Fix them one at a time -- run the tool, read the FIRST error, fix the smallest thing, rerun -- until all four gates are green. The launcher reruns all four tools itself to check your work.'

    _GATES = [
        ("ruff check .",          ["ruff", "check", "."]),
        ("ruff format --check .", ["ruff", "format", "--check", "."]),
        ("ty check .",            ["ty", "check", "."]),
        ("pytest -q",             ["pytest", "-q"]),
    ]

    def _missing_tools(self):
        return [t for t in ("ruff", "ty", "pytest") if shutil.which(t) is None]

    def _run_gate(self, args, repo_dir):
        try:
            r = subprocess.run(args, capture_output=True, text=True,
                               timeout=120, cwd=repo_dir)
        except subprocess.TimeoutExpired:
            return None, "timeout"
        return r.returncode, (r.stdout + "\n" + r.stderr).strip()

    def _check(self, repo_dir):
        missing = self._missing_tools()
        if missing:
            return None, [
                f"  Missing tool(s) on this machine: {', '.join(missing)}.",
                "  Install them the same way you installed your Python",
                "  toolchain in the env-setup-python activity:",
                "    uv tool install ruff",
                "    uv tool install ty",
                "    uv tool install pytest",
            ]
        for name, args in self._GATES:
            rc, out = self._run_gate(args, repo_dir)
            if rc is None:
                return None, [f"  {name} timed out."]
            if rc != 0:
                out_lines = out.splitlines()
                lines = [
                    f"  Gate FAILED: {name}",
                    "  Read the FIRST error below, fix the smallest thing it",
                    "  points at, then rerun the tool yourself inside the shell.",
                    "",
                ]
                lines += [f"    {ln}" for ln in out_lines[:20]]
                if len(out_lines) > 20:
                    lines.append(f"    ... ({len(out_lines)} lines total)")
                return None, lines
        passphrase = _decrypt("ruff-check=0|ruff-format=0|ty=0|pytest=0")
        if passphrase is not None:
            return passphrase, []
        return None, [
            "  All four gates passed but the passphrase did not unlock.",
            "  Contact your instructor.",
        ]


    def check(self, repo_dir):
        """Build+run the student's repo; return (passphrase_or_None, feedback_lines)."""
        return self._check(repo_dir)


ENGINE = ActivityEngine()


def main():
    _banner(ENGINE.title)
    print()
    input("  Press Enter to begin...")

    ok = run_shell_drop_validated(ENGINE.check)
    if not ok:
        sys.exit(0)


if __name__ == "__main__":
    main()
